+import type { Trait, TraitRecord, TraitValue } from '../trait/types';
+import type { World } from '../world';
+
+export const $aspect = Symbol('aspect');
+
+export type AspectInput = Trait | Aspect;
+export type Aspect<TTraits extends readonly Trait[] = readonly Trait[]> = {
+    readonly id: number;
+    readonly traits: TTraits;
+    readonly schema: Record<string, unknown>;
+    readonly [$aspect]: true;
+} & ((params?: AspectValue<TTraits>) => [Aspect<TTraits>, AspectValue<TTraits>]);
+
+export type AspectValue<TTraits extends readonly Trait[] = readonly Trait[]> = Partial<
+    UnionToIntersection<TraitRecord<TTraits[number]>>
+>;
+type UnionToIntersection<T> = (T extends unknown ? (x: T) => void : never) extends (
+    x: infer R
+) => void
+    ? R
+    : never;
+
+let aspectId = 0;
+
+export function isAspect(value: unknown): value is Aspect {
+    return !!(value as Aspect | null | undefined)?.[$aspect];
+}
+
+export function createAspect<T extends [AspectInput, AspectInput, ...AspectInput[]]>(
+    ...inputs: T
+): Aspect<FlattenAspectTraits<T>> {
+    const traits: Trait[] = [];
+    for (const input of inputs) {
+        const constituents = isAspect(input) ? input.traits : [input];
+        for (const constituent of constituents) {
+            if (isRelation(constituent) || constituent[$internal].relation) {
+                throw new Error('Koota: Relations cannot be constituents of an aspect.');
+            }
+            traits.push(constituent);
+        }
+    }
+
+    const schema: Record<string, unknown> = {};
+    for (const constituent of traits) {
+        const constituentSchema = constituent.schema;
+        if (typeof constituentSchema === 'function') continue;
+        for (const key of Object.keys(constituentSchema)) {
+            if (key in schema) {
+                throw new Error(`Koota: Aspect constituents cannot share the field "${key}".`);
+            }
+            schema[key] = (constituentSchema as Record<string, unknown>)[key];
+        }
+    }
+
+    const id = aspectId++;
+    const aspect = Object.assign((params: AspectValue<any> = {}) => [aspect, params] as const, {
+        [$aspect]: true as const,
+        id,
+        traits: Object.freeze(traits.slice()),
+        schema: Object.freeze(schema),
+    });
+    return aspect as Aspect<FlattenAspectTraits<T>>;
+}
+
+type FlattenOne<T> = T extends Aspect<infer Traits> ? Traits[number] : T extends Trait ? T : never;
+export type FlattenAspectTraits<T extends readonly AspectInput[]> = {
+    [K in keyof T]: FlattenOne<T[K]>;
+} extends infer R
+    ? R extends readonly Trait[]
+        ? R
+        : readonly Trait[]
+    : readonly Trait[];
+
+export function hasAspect(world: World, entity: Entity, aspect: Aspect): boolean {
+    return aspect.traits.every((trait) => hasTrait(world, entity, trait));
+}
+
+export function getAspect(world: World, entity: Entity, aspect: Aspect): Record<string, unknown> | undefined {
+    if (!hasAspect(world, entity, aspect)) return undefined;
+    const result: Record<string, unknown> = {};
+    for (const trait of aspect.traits) Object.assign(result, getTrait(world, entity, trait));
+    return result;
+}
+
+export function setAspect(world: World, entity: Entity, aspect: Aspect, value: any, triggerChanged = true) {
+    value = value instanceof Function ? value(getAspect(world, entity, aspect)) : value;
+    for (const trait of aspect.traits) {
+        const part = pickTraitValue(trait, value);
+        if (Object.keys(part).length) setTrait(world, entity, trait, part, triggerChanged);
+    }
+}
+
+export function pickTraitValue(trait: Trait, value: Record<string, unknown> | undefined) {
+    const result: Record<string, unknown> = {};
+    if (!value || typeof trait.schema === 'function') return result;
+    for (const key of Object.keys(trait.schema)) {
+        if (key in value) result[key] = value[key];
+    }
+    return result;
+}
