+/** Query-result path for composite parameters. Aspects deliberately retain one
+ * callback slot, rather than leaking their constituent storage layout. */
+function createAspectQueryResult(
+    world: World,
+    entities: Entity[],
+    params: QueryParameter[]
+): QueryResult<any> {
+    const results = Object.assign(entities, {
+        readEach(callback: (state: any[], entity: Entity, index: number) => void) {
+            for (let i = 0; i < entities.length; i++) {
+                const entity = entities[i];
+                callback(readAspectState(entity, params), entity, i);
+            }
+            return results;
+        },
+        updateEach(callback: (state: any[], entity: Entity, index: number) => void) {
+            for (let i = 0; i < entities.length; i++) {
+                const entity = entities[i];
+                const state = readAspectState(entity, params);
+                callback(state, entity, i);
+                if (!world.has(entity)) continue;
+                let stateIndex = 0;
+                for (const param of params) {
+                    if (isAspect(param)) {
+                        entity.set(param, state[stateIndex++]);
+                    } else if (!isModifier(param) && !isRelationPair(param)) {
+                        if ((param as Trait)[$internal].type !== 'tag') entity.set(param as Trait, state[stateIndex++]);
+                    }
+                }
+            }
+            return results;
+        },
+        useStores(callback: any) {
+            const aspectTraits = params.flatMap((param) =>
+                isAspect(param) ? param.traits.filter((trait) => trait[$internal].type !== 'tag') : []
+            );
+            callback(aspectTraits.map((trait) => getStore(world, trait)), entities);
+            return results;
+        },
+        select(...selected: QueryParameter[]) {
+            return createAspectQueryResult(world, entities, selected);
+        },
+        sort(
+            callback: (a: Entity, b: Entity) => number = (a, b) => getEntityId(a) - getEntityId(b)
+        ) {
+            Array.prototype.sort.call(entities, callback);
+            return results;
+        },
+    });
+    return results as QueryResult<any>;
+}
+
+function readAspectState(entity: Entity, params: QueryParameter[]) {
+    const state: any[] = [];
+    for (const param of params) {
+        if (isAspect(param)) state.push(entity.get(param));
+        else if (!isModifier(param) && !isRelationPair(param) && (param as Trait)[$internal].type !== 'tag') {
+            state.push(entity.get(param as Trait));
+        }
+    }
+    return state;
+}
